-- Additive reporting runtime hardening: published viewing is distinct from draft administration.
create or replace function public.report_member_in_scope(p_user uuid,p_t uuid,p_o uuid,p_f uuid) returns boolean language sql stable security definer set search_path=public as $$ select p_user is not null and exists(select 1 from public.memberships m where m.user_id=p_user and m.active and m.tenant_id=p_t and (m.organization_id is null or m.organization_id=p_o) and (m.facility_id is null or m.facility_id=p_f)); $$;
create or replace function public.validate_report_definition(p_definition jsonb,p_module text) returns boolean language plpgsql security definer set search_path=public as $$ declare c jsonb; x jsonb; allowed text[]:=array['equals','in','between','contains','gte','lte']; aggs text[]:=array['count','sum','average','median','min','max','percentage','sla_compliance','overdue','closed','open','pending','risk_distribution','trend']; begin if jsonb_typeof(p_definition)<>'object' or p_definition::text ~* '(select |insert |update |delete |drop |javascript|<script|;|\\$\\$)' then return false; end if; if exists(select 1 from jsonb_array_elements(coalesce(p_definition->'filters','[]')) x where x->>'operator'<>all(allowed) or x->>'field' !~ '^[a-z][a-z0-9_]{0,63}$') then return false; end if; if exists(select 1 from jsonb_array_elements(coalesce(p_definition->'columns','[]')) x where x->>'sourceField' !~ '^[a-z][a-z0-9_]{0,63}$' or coalesce((x->>'confidential')::boolean,false) and coalesce((x->>'visible')::boolean,true)) then return false; end if; if exists(select 1 from jsonb_array_elements(coalesce(p_definition->'calculations','[]')) x where x->>'operation'<>all(aggs) or coalesce(x->>'expression','')<>'') then return false; end if; if coalesce((p_definition->>'pageSize')::int,50) not between 1 and 200 or jsonb_array_length(coalesce(p_definition->'groupBy','[]'))>5 or p_definition ? 'table' or p_definition ? 'sql' then return false; end if; return p_module in ('medication_errors','inspections','drug_recalls','crash_cart','capa','policies','pharmacy_trolley','floor_stock','employee_management'); end $$;
create or replace function public.enforce_reporting_hierarchy() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_table_name='report_definitions' and new.current_version_id is not null and not exists(select 1 from public.report_versions v where v.id=new.current_version_id and v.definition_id=new.id and v.status='published' and v.tenant_id=new.tenant_id and v.organization_id=new.organization_id and v.facility_id is not distinct from new.facility_id) then raise exception 'Invalid current report version' using errcode='23503'; end if; if tg_table_name='dashboard_widgets' and new.report_version_id is not null and not exists(select 1 from public.report_versions v where v.id=new.report_version_id and v.status='published' and v.tenant_id=new.tenant_id and v.organization_id=new.organization_id and v.facility_id is not distinct from new.facility_id) then raise exception 'Widget report version scope mismatch' using errcode='23503'; end if; if tg_table_name in ('saved_reports','report_runs') and not exists(select 1 from public.report_versions v where v.id=new.report_version_id and v.status='published' and v.tenant_id=new.tenant_id and v.organization_id=new.organization_id and v.facility_id is not distinct from new.facility_id) then raise exception 'Report dependency scope mismatch' using errcode='23503'; end if; if tg_table_name='report_exports' and new.report_run_id is not null and not exists(select 1 from public.report_runs r where r.id=new.report_run_id and r.tenant_id=new.tenant_id and r.organization_id=new.organization_id and r.facility_id is not distinct from new.facility_id) then raise exception 'Export run scope mismatch' using errcode='23503'; end if; return new; end $$;
create or replace function public.prevent_direct_reporting_mutation() returns trigger language plpgsql security definer set search_path=public as $$ begin if current_setting('app.reporting_controlled',true)<>'on' and ((tg_table_name='report_definitions' and (new.current_version_id is distinct from old.current_version_id or old.status='published')) or (tg_table_name='dashboard_definitions' and old.status='published') or (tg_table_name='dashboard_widgets' and exists(select 1 from public.dashboard_definitions d where d.id=old.dashboard_id and d.status='published')) or (tg_table_name='report_runs' and (new.status is distinct from old.status or new.requested_by is distinct from old.requested_by)) or (tg_table_name='report_exports' and (new.status is distinct from old.status or new.requested_by is distinct from old.requested_by or new.storage_key is distinct from old.storage_key))) then raise exception 'Reporting mutation requires a controlled function'; end if; return new; end $$;
create trigger report_definitions_hierarchy before insert or update on public.report_definitions for each row execute function public.enforce_reporting_hierarchy(); create trigger dashboard_widgets_hierarchy before insert or update on public.dashboard_widgets for each row execute function public.enforce_reporting_hierarchy(); create trigger saved_reports_hierarchy before insert or update on public.saved_reports for each row execute function public.enforce_reporting_hierarchy(); create trigger report_runs_hierarchy before insert or update on public.report_runs for each row execute function public.enforce_reporting_hierarchy(); create trigger report_exports_hierarchy before insert or update on public.report_exports for each row execute function public.enforce_reporting_hierarchy();
create trigger report_definitions_direct_guard before update on public.report_definitions for each row execute function public.prevent_direct_reporting_mutation(); create trigger dashboards_direct_guard before update on public.dashboard_definitions for each row execute function public.prevent_direct_reporting_mutation(); create trigger dashboard_widgets_direct_guard before update on public.dashboard_widgets for each row execute function public.prevent_direct_reporting_mutation(); create trigger report_runs_direct_guard before update on public.report_runs for each row execute function public.prevent_direct_reporting_mutation(); create trigger report_exports_direct_guard before update on public.report_exports for each row execute function public.prevent_direct_reporting_mutation();
drop policy if exists report_definitions_read on public.report_definitions; drop policy if exists report_versions_read on public.report_versions; drop policy if exists dashboards_read on public.dashboard_definitions; drop policy if exists dashboard_widgets_read on public.dashboard_widgets;
create policy report_definitions_published_view on public.report_definitions for select using(status='published' and public.can_report('reports.view',tenant_id,organization_id,facility_id)); create policy report_definitions_manage on public.report_definitions for select using(public.can_report('reports.edit',tenant_id,organization_id,facility_id) or public.can_report('reports.publish',tenant_id,organization_id,facility_id)); create policy report_versions_published_view on public.report_versions for select using(status='published' and public.can_report('reports.view',tenant_id,organization_id,facility_id)); create policy report_versions_manage on public.report_versions for select using(public.can_report('reports.edit',tenant_id,organization_id,facility_id) or public.can_report('reports.publish',tenant_id,organization_id,facility_id)); create policy dashboards_published_view on public.dashboard_definitions for select using(status='published' and public.can_report('dashboards.view',tenant_id,organization_id,facility_id)); create policy dashboards_manage on public.dashboard_definitions for select using(public.can_report('dashboards.manage',tenant_id,organization_id,facility_id)); create policy dashboard_widgets_published_view on public.dashboard_widgets for select using(exists(select 1 from public.dashboard_definitions d where d.id=dashboard_id and d.status='published') and public.can_report('dashboards.view',tenant_id,organization_id,facility_id)); create policy dashboard_widgets_manage on public.dashboard_widgets for select using(public.can_report('dashboards.manage',tenant_id,organization_id,facility_id));
create or replace function public.publish_report_version(p_definition_id uuid,p_version_id uuid) returns void language plpgsql security definer set search_path=public as $$ declare d public.report_definitions%rowtype; v public.report_versions%rowtype; begin select * into d from public.report_definitions where id=p_definition_id for update; select * into v from public.report_versions where id=p_version_id for update; if not found or v.definition_id<>d.id or v.status<>'approved' or not public.can_report('reports.publish',d.tenant_id,d.organization_id,d.facility_id) or not public.validate_report_definition(v.definition,d.module_key) then raise exception 'Report publication denied'; end if; perform set_config('app.reporting_controlled','on',true); update public.report_versions set status='published',updated_at=now(),updated_by=auth.uid() where id=v.id; update public.report_definitions set status='published',current_version_id=v.id,updated_at=now(),updated_by=auth.uid() where id=d.id; perform public.append_audit_event(d.tenant_id,d.organization_id,d.facility_id,'report.published','report_definition',d.id,jsonb_build_object('versionId',v.id)); end $$;
create or replace function public.request_report_run(p_version_id uuid,p_filters jsonb default '[]') returns uuid language plpgsql security definer set search_path=public as $$ declare v public.report_versions%rowtype; id uuid; begin select * into v from public.report_versions where id=p_version_id and status='published' for update; if not found or not public.can_report('reports.view',v.tenant_id,v.organization_id,v.facility_id) or not public.validate_report_definition(v.definition,(select module_key from public.report_definitions where id=v.definition_id)) then raise exception 'Report run denied'; end if; raise exception 'Report run requires trusted module adapter'; end $$;
create or replace function public.request_report_export(p_run_id uuid,p_format text,p_language text) returns uuid language plpgsql security definer set search_path=public as $$ declare r public.report_runs%rowtype; id uuid; begin select * into r from public.report_runs where id=p_run_id and requested_by=auth.uid() for update; if not found or r.status<>'completed' or not public.can_report('reports.export',r.tenant_id,r.organization_id,r.facility_id) or p_format not in ('pdf','excel','csv') or p_language not in ('ar','en','bilingual') then raise exception 'Report export denied'; end if; insert into public.report_exports(tenant_id,organization_id,facility_id,report_run_id,format,language,requested_by,expires_at) values(r.tenant_id,r.organization_id,r.facility_id,r.id,p_format,p_language,auth.uid(),now()+interval '24 hours') returning id into id; perform public.append_audit_event(r.tenant_id,r.organization_id,r.facility_id,'report.export_requested','report_run',r.id,jsonb_build_object('format',p_format)); return id; end $$;
revoke all on function public.report_member_in_scope(uuid,uuid,uuid,uuid),public.validate_report_definition(jsonb,text),public.enforce_reporting_hierarchy(),public.prevent_direct_reporting_mutation() from public,anon,authenticated; revoke all on function public.publish_report_version(uuid,uuid),public.request_report_run(uuid,jsonb),public.request_report_export(uuid,text,text) from public,anon; grant execute on function public.publish_report_version(uuid,uuid),public.request_report_run(uuid,jsonb),public.request_report_export(uuid,text,text) to authenticated;
